{
  "evidence_repository": {
    "storage": {
      "backend": "s3",
      "bucket": "acme-vendor-evidence",
      "prefix": "diligence/",
      "encryption": "AES-256-SSE",
      "versioning": true
    },
    "metadata_db": {
      "connection_string_env": "EVIDENCE_DB_URL",
      "schema": "vendor_risk"
    },
    "document_types": {
      "soc2_type_ii":        { "green_months": 12, "amber_months": 18, "required_for_tiers": [1, 2] },
      "iso_27001":           { "green_months": 12, "amber_months": 18, "required_for_tiers": [1, 2] },
      "penetration_test":    { "green_months": 12, "amber_months": 18, "required_for_tiers": [1] },
      "bcp_dr_plan":         { "green_months": 12, "amber_months": 24, "required_for_tiers": [1, 2] },
      "financial_statement": { "green_months": 12, "amber_months": 15, "required_for_tiers": [1] },
      "subprocessor_list":   { "green_months": 6,  "amber_months": 12, "required_for_tiers": [1, 2, 3] }
    },
    "review_cadences": {
      "annual":      ["soc2_type_ii", "iso_27001", "bcp_dr_plan", "financial_statement"],
      "semi_annual": ["penetration_test"],
      "quarterly":   ["subprocessor_list"],
      "event_triggered": [
        { "trigger": "breach_disclosure",   "reassess": ["soc2_type_ii", "penetration_test"] },
        { "trigger": "vendor_ma",           "reassess": ["all"] },
        { "trigger": "scope_change",        "reassess": ["soc2_type_ii", "bcp_dr_plan"] }
      ]
